    #[test]
    fn test_env_projection_api_key_detection() {
        // Test API key detection from env vars
        let api_key_patterns = [
            "OPENAI_API_KEY",
            "ANTHROPIC_AUTH_TOKEN",
            "GEMINI_API_KEY",
            "MOONSHOT_API_KEY",
            "KILO_API_KEY",
