    fn test_env_projection_base_url_detection() {
        // Test base URL detection from env vars
        let base_url_patterns = [
            "OPENAI_BASE_URL",
            "ANTHROPIC_BASE_URL",
            "GOOGLE_GEMINI_BASE_URL",
            "KILO_BASE_URL",
