    fn test_8888_cloaking_port_configuration() {
        // Test port 8888 cloaking configuration
        let ports = vec![8888, 8880, 8443, 443];

        for port in &ports {
            assert!(*port > 0 && *port < 65536, "Port should be valid: {}", port);
        }

        // 8888 should be primary
