#[derive(Debug, Clone, Default)]
pub struct DSELMetrics {
    /// Total provider selections made
    pub total_selections: u64,
    /// Selections by provider name
    pub selections_by_provider: HashMap<String, u64>,
    /// Quota violations (requests that exceeded quota)
    pub quota_violations: u64,
    /// Hierarchical transformations applied
    pub hierarchical_transforms: u64,
    /// Token usage tracked
    pub total_tokens_tracked: u64,
    /// Rate limit hits
    pub rate_limit_hits: u64,
    /// Fallback selections (second choice or later)
    pub fallback_selections: u64,
}

impl DSELMetrics {
    pub fn new() -> Self {
        Self::default()
    }

    /// Record a provider selection
    pub fn record_selection(&mut self, provider: &str, is_fallback: bool) {
        self.total_selections += 1;
        *self.selections_by_provider.entry(provider.to_string()).or_insert(0) += 1;
        if is_fallback {
            self.fallback_selections += 1;
        }
    }

    /// Record quota violation
    pub fn record_quota_violation(&mut self) {
        self.quota_violations += 1;
    }

    /// Record hierarchical transformation
    pub fn record_hierarchical_transform(&mut self) {
        self.hierarchical_transforms += 1;
    }

    /// Record token tracking
    pub fn record_token_usage(&mut self, tokens: u64) {
        self.total_tokens_tracked += tokens;
    }

    /// Record rate limit hit
    pub fn record_rate_limit(&mut self) {
        self.rate_limit_hits += 1;
    }

    /// Get selection statistics
    pub fn get_selection_stats(&self) -> (u64, u64, f64) {
        let total = self.total_selections;
        let fallbacks = self.fallback_selections;
        let fallback_rate = if total > 0 {
            (fallbacks as f64 / total as f64) * 100.0
        } else {
            0.0
        };
        (total, fallbacks, fallback_rate)
    }

    /// Get top providers by usage
    pub fn get_top_providers(&self, limit: usize) -> Vec<(String, u64)> {
        let mut providers: Vec<_> = self.selections_by_provider.iter().collect();
        providers.sort_by(|a, b| b.1.cmp(a.1));
        providers.into_iter().take(limit).map(|(k, v)| (k.clone(), *v)).collect()
    }

